'use strict'

const {
  follow: followSchema,
  unfollow: unfollowSchema,
  followers: followersSchema
} = require('./schemas')

module.exports = async function (fastify, opts) {
  fastify.addHook('preHandler', fastify.authPreHandler)

  fastify
    .post('/follow', followSchema, followHandler)
    .post('/unfollow', unfollowSchema, unfollowHandler)
    .get('/following/me', getMyFollowingHandler)
    .get('/followers/me', getMyFollowersHandler)
    .get('/following/:userId', getUserFollowingHandler)
    .get('/followers/:userId', followersSchema, getUserFollowersHandler)
}

module.exports[Symbol.for('plugin-meta')] = {
  decorators: {
    fastify: [
      'redis',
      'authPreHandler'
    ]
  }
}

async function followHandler (req, reply) {
  const { userId } = req.body
  await this.followService.follow(req.user._id, userId)
  reply.code(204)
}

async function unfollowHandler (req, reply) {
  const { userId } = req.body
  await this.followService.unfollow(req.user._id, userId)
  reply.code(204)
}

function getMyFollowingHandler (req, reply) {
  return this.followService.getFollowing(req.user._id)
}

function getMyFollowersHandler (req, reply) {
  return this.followService.getFollowers(req.user._id)
}

function getUserFollowingHandler (req, reply) {
  return this.followService.getFollowing(req.params.userId)
}

function getUserFollowersHandler (req, reply) {
  return this.followService.getFollowers(req.params.userId)
}

'use strict'

const fp = require('fastify-plugin')
const Producer = require('./lib/producer')
const Consumer = require('./lib/consumer')

function fastifyKafka (fastify, opts, next) {
  fastify.decorate('kafka', {})

  if (opts.producer) {
    fastify.register(fp(buildProducer), opts)
  }

  if (opts.consumer) {
    fastify.register(fp(buildConsumer), opts)
  }

  next()
}

function buildProducer (fastify, opts, next) {
  const producer = new Producer(opts.producer, fastify.log, next, opts.producerTopicConf, opts.metadataOptions)
  fastify.kafka.producer = producer
  fastify.kafka.push = producer.push.bind(producer)

  fastify.addHook('onClose', onClose)
  function onClose (fastify, done) {
    fastify.kafka.producer.stop(done)
  }
}

function buildConsumer (fastify, opts, next) {
  const consumer = new Consumer(opts.consumer, fastify.log, next, opts.consumerTopicConf, opts.metadataOptions)
  fastify.kafka.consumer = consumer
  fastify.kafka.consume = consumer.consume.bind(consumer)
  fastify.kafka.subscribe = consumer.subscribe.bind(consumer)
  fastify.kafka.on = consumer.on.bind(consumer)

  fastify.addHook('onClose', onClose)
  function onClose (fastify, done) {
    fastify.kafka.consumer.stop(done)
  }
}

module.exports = fp(fastifyKafka, {
  fastify: '5.x',
  name: '@fastify/kafka'
})
module.exports.default = fastifyKafka
module.exports.fastifyKafka = fastifyKafka

import { FastifyPluginAsync, FastifyInstance, FastifyBaseLogger, FastifyRequest, FastifyReply } from 'fastify'

declare module 'fastify' {
  interface FastifyInstance {
    fetch: fastifyFetch.FetchRoutes
  }
}

type FastifyFetchPlugin = FastifyPluginAsync<NonNullable<fastifyFetch.FastifyFetchOptions>>

declare namespace fastifyFetch {
  export interface FetchContext {
    log: FastifyBaseLogger
    server: FastifyInstance
    params: Record<string, string>
    query: Record<string, string>
    request: FastifyRequest
    reply: FastifyReply
  }

  export type FetchHandler = (request: Request, ctx: FetchContext) => Response | Promise<Response>

  export interface FetchRoutes {
    get(path: string, handler: FetchHandler): void
    post(path: string, handler: FetchHandler): void
    put(path: string, handler: FetchHandler): void
    delete(path: string, handler: FetchHandler): void
    patch(path: string, handler: FetchHandler): void
    options(path: string, handler: FetchHandler): void
    head(path: string, handler: FetchHandler): void
  }

  export interface FastifyFetchOptions {
  }

  export const fastifyFetch: FastifyFetchPlugin

  export { fastifyFetch as default }
}

declare function fastifyFetch (...params: Parameters<FastifyFetchPlugin>): ReturnType<FastifyFetchPlugin>

export = fastifyFetch

